UPDATE inventory_stock_log
SET deduct_retry_count=deduct_retry_count+1, update_time=NOW()
WHERE order_id=#{orderId} AND sku_id=#{skuId} AND status = 'DEDUCT_FAIL' AND deduct_retry_count  <  #{deductMaxCount}

UPDATE inventory_stock_log
SET status='DEDUCT_FAIL_MAX_RETRY', update_time=NOW()
WHERE order_id=#{orderId} AND sku_id=#{skuId} AND status = 'DEDUCT_FAIL' AND deduct_retry_count  >=  #{deductMaxCount}

UPDATE inventory_stock_log
SET rollback_retry_count=rollback_retry_count+1, update_time=NOW()
WHERE order_id=#{orderId} AND sku_id=#{skuId} AND status = 'ROLLBACK_FAIL' AND rollback_retry_count  <  #{rollbackMaxCount}

UPDATE inventory_stock_log
SET status='ROLLBACK_FAIL_MAX_RETRY', update_time=NOW()
WHERE order_id=#{orderId} AND sku_id=#{skuId} AND status = 'ROLLBACK_FAIL' AND rollback_retry_count  >=  #{rollbackMaxCount}

UPDATE inventory_stock_log
SET status='UNKNOWN_ERROR', update_time=NOW()
WHERE order_id=#{orderId} AND sku_id=#{skuId}
